		if ticked then
			AntiRagdollTickBox.BackgroundColor3 = accentColor
		else
			AntiRagdollTickBox.BackgroundColor3 = Color3.new(0, 0, 0)
		end
	end
	
	local function enableAntiRagdoll()
		local character = LocalPlayer.Character
		if not character then return end
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		if not humanoid then return end
	
		steppedConnection = RunService.Stepped:Connect(function()
			if not isEnabled then return end
			local chr = LocalPlayer.Character
			if not chr then return end
			local hum = chr:FindFirstChildOfClass("Humanoid")
			if not hum then return end
	
			-- Disable ragdoll states
			hum:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
			hum:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
	
			-- Remove any BallSocketConstraints or HingeConstraints added by ragdoll systems
			for _, part in pairs(chr:GetDescendants()) do
				if part:IsA("BallSocketConstraint") or part:IsA("HingeConstraint") then
					if part:FindFirstAncestorOfClass("Motor6D") == nil then
						part.Enabled = false
					end
				end
			end
	
			-- Keep humanoid upright
			if hum:GetState() == Enum.HumanoidStateType.Ragdoll or
				hum:GetState() == Enum.HumanoidStateType.FallingDown then
				hum:ChangeState(Enum.HumanoidStateType.GettingUp)
			end
		end)
	end
	
	local function disableAntiRagdoll()
		if steppedConnection then
			steppedConnection:Disconnect()
			steppedConnection = nil
		end
	
		local character = LocalPlayer.Character
		if not character then return end
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		if not humanoid then return end
	
		humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, true)
		humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
	
		for _, part in pairs(character:GetDescendants()) do
			if part:IsA("BallSocketConstraint") or part:IsA("HingeConstraint") then
				part.Enabled = true
			end
		end
	end
	
	AntiRagdollTickBox.MouseButton1Click:Connect(function()
		isEnabled = not isEnabled
		setTickboxState(isEnabled)
	
		if isEnabled then
			enableAntiRagdoll()
		else
			disableAntiRagdoll()
		end
	end)
	
	LocalPlayer.CharacterAdded:Connect(function()
		if isEnabled then
			task.wait(0.1)
			enableAntiRagdoll()
		end
	end)
	
	script.Parent.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			isEnabled = false
			disableAntiRagdoll()
		end
	end)
end;
