			dochar(character)
		end
	
		charaddedConnection = LocalPlayer.CharacterAdded:Connect(function(newCharacter)
			dochar(newCharacter)
		end)
	
		steppedConnection = RunService.Stepped:Connect(function()
			local chr = LocalPlayer.Character
			if chr ~= nil and chr:FindFirstChildWhichIsA("BasePart") then
				local part = chr:FindFirstChild("HumanoidRootPart") or chr:FindFirstChildWhichIsA("BasePart")
				local cfr = (chr:FindFirstChild("HumanoidRootPart") and chr.HumanoidRootPart.CFrame) or chr:GetPivot()
				charcframe = cfr
	
				if cfr.Position.Y < destroyheightnew then
					fixchar(chr, part, destroyheightnew)
				end
	
				local partvel = part.Velocity
				if (partvel.Y / fpsdiv) + part.Position.Y < destroyheightnew then
					fixchar(chr, part, destroyheightnew)
				end
			end
		end)
	end
	
	local function disableAntiVoid()
		stopped = true
		workspace.FallenPartsDestroyHeight = originalDestroyHeight
	
		if steppedConnection then
			steppedConnection:Disconnect()
			steppedConnection = nil
		end
		if charaddedConnection then
			charaddedConnection:Disconnect()
			charaddedConnection = nil
		end
		for _, v in pairs(connectsextra) do
			v:Disconnect()
		end
		connectsextra = {}
	end
	
	AntiVoidTickBox.MouseButton1Click:Connect(function()
		isEnabled = not isEnabled
		setTickboxState(isEnabled)
	
		if isEnabled then
			enableAntiVoid()
		else
			disableAntiVoid()
		end
	end)
	
	LocalPlayer.CharacterAdded:Connect(function()
		if isEnabled then
			originalDestroyHeight = workspace.FallenPartsDestroyHeight ~= -50000 and workspace.FallenPartsDestroyHeight or originalDestroyHeight
		end
	end)
	
	script.Parent.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			if isEnabled then
				disableAntiVoid()
			end
		end
	end)
end;
