		if isMinimized then
			CharacterGroup.Size = minimizedSize
			for _, row in ipairs(rows) do
				row.Visible = false
			end
			CharacterMinimize.Text = "+"
		else
			CharacterGroup.Size = originalSize
			for _, row in ipairs(rows) do
				row.Visible = true
			end
			CharacterMinimize.Text = "-"
		end
	end)
