-- StarterGui.AgarWareGui.MainFrame.ContentArea.TCOMainPage.TCOMainLeftSide.MainGroup.ADODeathRow.ADODeathScript
local function C_e8()
local script = G2L["e8"];
	-- ============================================================
	-- AUTO DROP ON DEATH SCRIPT
	-- Drops ALL tools (including Enlighten) on death.
	-- Picks them back up as fast as possible on respawn.
	-- ============================================================
	
	local Players = game:GetService("Players")
	local LocalPlayer = Players.LocalPlayer
	local ADODeathRow = script.Parent
	local ADODeathTickBox = ADODeathRow.ADODeathTickBox
	local ADODeathText = ADODeathRow.ADODeathText
	local MainGroup = ADODeathRow.Parent
	local MainAccentColor = MainGroup.MainAccentColor
	
	-- ============================================================
	-- SCREENGUI HELPER
	-- ============================================================
	local function getScreenGui()
		local p = script.Parent
		while p do
			if p:IsA("ScreenGui") then return p end
			p = p.Parent
		end
	end
	
	-- ============================================================
	-- TOOLTIP
	-- ============================================================
	local tooltipFrame = Instance.new("Frame")
	tooltipFrame.BackgroundColor3 = Color3.fromRGB(16, 16, 16)
	tooltipFrame.BorderSizePixel = 0
	tooltipFrame.ZIndex = 100
	tooltipFrame.AutomaticSize = Enum.AutomaticSize.Y
	tooltipFrame.Size = UDim2.new(0, 212, 0, 0)
	tooltipFrame.Visible = false
	tooltipFrame.Parent = getScreenGui()
	
	local tooltipStroke = Instance.new("UIStroke", tooltipFrame)
	tooltipStroke.Color = Color3.fromRGB(57, 57, 57)
	
	local tooltipPadding = Instance.new("UIPadding", tooltipFrame)
	tooltipPadding.PaddingTop = UDim.new(0, 6)
	tooltipPadding.PaddingBottom = UDim.new(0, 6)
	tooltipPadding.PaddingLeft = UDim.new(0, 6)
	tooltipPadding.PaddingRight = UDim.new(0, 6)
	
	local tooltipLabel = Instance.new("TextLabel", tooltipFrame)
	tooltipLabel.BackgroundTransparency = 1
	tooltipLabel.Text = "Auto drops all of your tools on death. Instantly picks it back up after respawn."
	tooltipLabel.TextColor3 = Color3.new(1, 1, 1)
	tooltipLabel.TextSize = 14
	tooltipLabel.TextXAlignment = Enum.TextXAlignment.Left
	tooltipLabel.TextYAlignment = Enum.TextYAlignment.Top
	tooltipLabel.Font = Enum.Font.GothamSemibold
	tooltipLabel.TextWrapped = true
	tooltipLabel.Size = UDim2.new(0, 200, 0, 0)
	tooltipLabel.AutomaticSize = Enum.AutomaticSize.Y
	tooltipLabel.ZIndex = 101
	
	ADODeathTickBox.MouseEnter:Connect(function()
		local abs = ADODeathTickBox.AbsolutePosition
		local size = ADODeathTickBox.AbsoluteSize
		tooltipFrame.Position = UDim2.new(0, abs.X + size.X + 10, 0, abs.Y)
		tooltipFrame.Visible = true
	end)
	ADODeathTickBox.MouseLeave:Connect(function()
		tooltipFrame.Visible = false
	end)
	
	-- ============================================================
	-- STATE
	-- ============================================================
	local isEnabled  = false
	local charConn   = nil
	local TAG        = "ADODeathDropped"
	
	-- ============================================================
	-- DROP ALL TOOLS (death)
	-- ============================================================
	local function dropAllTools()
		local char = LocalPlayer.Character
		if not char then return end
	
		-- Pull backpack into character so everything is in one place
		for _, tool in ipairs(LocalPlayer.Backpack:GetChildren()) do
			if tool:IsA("Tool") then
				tool.Parent = char
			end
		end
	
		task.wait(0.05)
	
		-- Drop every tool into workspace, Enlighten included
		for _, tool in ipairs(char:GetChildren()) do
			if tool:IsA("Tool") then
				tool:AddTag(TAG)
				tool.Parent = workspace
			end
		end
	end
	
	-- ============================================================
	-- PICKUP TOOLS (respawn)
	-- Tries immediately, then retries every 0.1s for up to 3s
	-- so tools are grabbed the moment the humanoid is ready,
	-- before other players can snatch them.
	-- ============================================================
	local function pickupDroppedTools(char)
		local deadline = tick() + 3  -- give up after 3 seconds
	
		repeat
			local hum = char:FindFirstChildWhichIsA("Humanoid")
			if hum and hum.Health > 0 then
				for _, obj in ipairs(workspace:GetChildren()) do
					if obj:IsA("Tool") and obj:HasTag(TAG) and obj:FindFirstChild("Handle") then
						hum:EquipTool(obj)
					end
				end
				-- Check if any tagged tools are still in workspace
				local remaining = false
				for _, obj in ipairs(workspace:GetChildren()) do
					if obj:IsA("Tool") and obj:HasTag(TAG) then
						remaining = true
						break
					end
				end
				if not remaining then break end  -- all picked up, done
			end
			task.wait(0.1)
		until tick() > deadline or not isEnabled
	end
	
	-- ============================================================
	-- CHARACTER SETUP
	-- ============================================================
	local function setupCharacter(char)
		-- Start pickup attempt immediately — don't wait for humanoid first
		task.spawn(function()
			pickupDroppedTools(char)
		end)
	
		-- Watch for death on this character
		local hum = char:FindFirstChildWhichIsA("Humanoid")
			or char:WaitForChild("Humanoid", 10)
		if not hum then return end
	
		hum.Died:Connect(function()
			if not isEnabled then return end
			task.wait(0.05)
			dropAllTools()
		end)
	end
	
	-- ============================================================
	-- ENABLE / DISABLE
	-- ============================================================
	local function enable()
		isEnabled = true
		ADODeathTickBox.BackgroundColor3 = MainAccentColor.BackgroundColor3
	
		if LocalPlayer.Character then
			setupCharacter(LocalPlayer.Character)
		end
	
		charConn = LocalPlayer.CharacterAdded:Connect(function(char)
			if isEnabled then
				setupCharacter(char)
			end
		end)
	end
	
	local function disable()
		isEnabled = false
		ADODeathTickBox.BackgroundColor3 = Color3.new(0, 0, 0)
	
		if charConn then
			charConn:Disconnect()
			charConn = nil
		end
	end
	
	-- ============================================================
	-- TICKBOX TOGGLE
	-- ============================================================
	ADODeathTickBox.MouseButton1Click:Connect(function()
		if isEnabled then
			disable()
		else
			enable()
		end
	end)
	
	-- ============================================================
	-- CLEANUP
	-- ============================================================
	script.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			if isEnabled then disable() end
			tooltipFrame:Destroy()
		end
	end)
end;
task.spawn(C_e8);
-- StarterGui.AgarWareGui.MainFrame.ContentArea.TCOMainPage.TCOMainLeftSide.MainGroup.APickupRow.APickupScript
local function C_ec()
local script = G2L["ec"];
	-- ============================================================
	-- AUTO PICKUP SCRIPT (INSTANT PICKUP - NO WAITS)
	-- Automatically picks up ALL dropped tools at once and unequips them
	-- Only unequips tools that were AUTO PICKED UP
	-- ============================================================
	
	local Players = game:GetService("Players")
	local LocalPlayer = Players.LocalPlayer
	local APickupRow = script.Parent
	local APickupTickBox = APickupRow.APickupTickBox
	local MainGroup = APickupRow.Parent
	local MainAccentColor = MainGroup.MainAccentColor
	
	-- Tag used by Auto Drop on Death script
	local DEATH_TAG = "ADODeathDropped"
	
	-- ============================================================
	-- SCREENGUI HELPER
	-- ============================================================
	local function getScreenGui()
		local p = script.Parent
		while p do
			if p:IsA("ScreenGui") then return p end
			p = p.Parent
		end
	end
	
	-- ============================================================
	-- TOOLTIP
	-- ============================================================
	local tooltipFrame = Instance.new("Frame")
	tooltipFrame.BackgroundColor3 = Color3.fromRGB(16, 16, 16)
	tooltipFrame.BorderSizePixel = 0
	tooltipFrame.ZIndex = 100
	tooltipFrame.AutomaticSize = Enum.AutomaticSize.Y
	tooltipFrame.Size = UDim2.new(0, 212, 0, 0)
	tooltipFrame.Visible = false
	tooltipFrame.Parent = getScreenGui()
	
	local tooltipStroke = Instance.new("UIStroke", tooltipFrame)
	tooltipStroke.Color = Color3.fromRGB(57, 57, 57)
	
	local tooltipPadding = Instance.new("UIPadding", tooltipFrame)
	tooltipPadding.PaddingTop = UDim.new(0, 6)
	tooltipPadding.PaddingBottom = UDim.new(0, 6)
	tooltipPadding.PaddingLeft = UDim.new(0, 6)
	tooltipPadding.PaddingRight = UDim.new(0, 6)
	
	local tooltipLabel = Instance.new("TextLabel", tooltipFrame)
	tooltipLabel.BackgroundTransparency = 1
	tooltipLabel.Text = "Automatically picks up all tools that players drop."
	tooltipLabel.TextColor3 = Color3.new(1, 1, 1)
	tooltipLabel.TextSize = 14
	tooltipLabel.TextXAlignment = Enum.TextXAlignment.Left
	tooltipLabel.TextYAlignment = Enum.TextYAlignment.Top
	tooltipLabel.Font = Enum.Font.GothamSemibold
	tooltipLabel.TextWrapped = true
	tooltipLabel.Size = UDim2.new(0, 200, 0, 0)
	tooltipLabel.AutomaticSize = Enum.AutomaticSize.Y
	tooltipLabel.ZIndex = 101
	
	APickupTickBox.MouseEnter:Connect(function()
		local abs = APickupTickBox.AbsolutePosition
		local size = APickupTickBox.AbsoluteSize
		tooltipFrame.Position = UDim2.new(0, abs.X + size.X + 10, 0, abs.Y)
		tooltipFrame.Visible = true
	end)
	APickupTickBox.MouseLeave:Connect(function()
		tooltipFrame.Visible = false
	end)
	
	-- ============================================================
	-- STATE
	-- ============================================================
	local isEnabled = false
	local pickupLoop = nil
	local unequipLoop = nil
	local autoPickedTools = {}  -- Tools that were picked up by auto pickup (with expiry time)
	
	-- ============================================================
	-- UNEQUIP LOOP (SEPARATE FROM PICKUP)
	-- ============================================================
	local function startUnequipLoop()
		unequipLoop = task.spawn(function()
			while isEnabled do
				local char = LocalPlayer.Character
	
				if char then
					local currentTime = tick()
	
					-- Clean up expired tools
					for tool, expiry in pairs(autoPickedTools) do
						if currentTime > expiry then
							autoPickedTools[tool] = nil
						end
					end
	
					-- Unequip auto-picked tools
					for _, tool in pairs(char:GetChildren()) do
						if tool:IsA("Tool") and autoPickedTools[tool] and currentTime < autoPickedTools[tool] then
							tool.Parent = LocalPlayer.Backpack
						end
					end
				end
	
				task.wait()
			end
		end)
	end
	
	-- ============================================================
	-- AUTO PICKUP LOOP
	-- ============================================================
	local function startPickupLoop()
		pickupLoop = task.spawn(function()
			while isEnabled do
				local char = LocalPlayer.Character
				local hum = char and char:FindFirstChildWhichIsA("Humanoid")
	
				if hum and hum.Health > 0 then
					local currentTool = char:FindFirstChildOfClass("Tool")
	
					-- Pick up ALL tools from workspace
					for _, obj in ipairs(workspace:GetChildren()) do
						if obj:IsA("Tool") and obj:FindFirstChild("Handle") and not obj:HasTag(DEATH_TAG) then
							autoPickedTools[obj] = tick() + 0.5
	
							pcall(function()
								hum:EquipTool(obj)
							end)
						end
					end
	
					-- Re-equip current tool if we had one
					if currentTool and currentTool.Parent == LocalPlayer.Backpack and not autoPickedTools[currentTool] then
						task.wait(0.05)
						hum:EquipTool(currentTool)
					end
				end
	
				task.wait(0.1)
			end
		end)
	end
	
	-- ============================================================
	-- ENABLE / DISABLE
	-- ============================================================
	local function enable()
		isEnabled = true
		APickupTickBox.BackgroundColor3 = MainAccentColor.BackgroundColor3
		autoPickedTools = {}
		startPickupLoop()
		startUnequipLoop()
	end
	
	local function disable()
		isEnabled = false
		APickupTickBox.BackgroundColor3 = Color3.new(0, 0, 0)
	
		if pickupLoop then
			task.cancel(pickupLoop)
			pickupLoop = nil
		end
	
		if unequipLoop then
			task.cancel(unequipLoop)
			unequipLoop = nil
		end
	
		autoPickedTools = {}
	end
	
	-- ============================================================
	-- TICKBOX TOGGLE
	-- ============================================================
	APickupTickBox.MouseButton1Click:Connect(function()
		if isEnabled then
			disable()
		else
			enable()
		end
	end)
	
	-- ============================================================
	-- CLEANUP
	-- ============================================================
	script.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			if isEnabled then disable() end
			tooltipFrame:Destroy()
		end
	end)
end;
task.spawn(C_ec);
-- StarterGui.AgarWareGui.MainFrame.ContentArea.TCOMainPage.TCOMainLeftSide.MainGroup.AntiEnliRow.AntiEnliScript
local function C_f0()
local script = G2L["f0"];
	-- ============================================================
	-- ANTI ENLIGHTEN DROP SCRIPT
	-- Prevents you from dropping Enlighten (The Arkenstone)
	-- ============================================================
	
	local Players = game:GetService("Players")
	local LocalPlayer = Players.LocalPlayer
	local AntiEnliRow = script.Parent
	local AntiEnliTickBox = AntiEnliRow.AntiEnliTickBox
	local MainGroup = AntiEnliRow.Parent
	local MainAccentColor = MainGroup.MainAccentColor
	
	-- ============================================================
	-- SCREENGUI HELPER
	-- ============================================================
	local function getScreenGui()
		local p = script.Parent
		while p do
			if p:IsA("ScreenGui") then return p end
			p = p.Parent
		end
	end
	
	-- ============================================================
	-- TOOLTIP
	-- ============================================================
	local tooltipFrame = Instance.new("Frame")
	tooltipFrame.BackgroundColor3 = Color3.fromRGB(16, 16, 16)
	tooltipFrame.BorderSizePixel = 0
	tooltipFrame.ZIndex = 100
	tooltipFrame.AutomaticSize = Enum.AutomaticSize.Y
	tooltipFrame.Size = UDim2.new(0, 212, 0, 0)
	tooltipFrame.Visible = false
	tooltipFrame.Parent = getScreenGui()
	
	local tooltipStroke = Instance.new("UIStroke", tooltipFrame)
	tooltipStroke.Color = Color3.fromRGB(57, 57, 57)
	
	local tooltipPadding = Instance.new("UIPadding", tooltipFrame)
	tooltipPadding.PaddingTop = UDim.new(0, 6)
	tooltipPadding.PaddingBottom = UDim.new(0, 6)
	tooltipPadding.PaddingLeft = UDim.new(0, 6)
	tooltipPadding.PaddingRight = UDim.new(0, 6)
	
	local tooltipLabel = Instance.new("TextLabel", tooltipFrame)
	tooltipLabel.BackgroundTransparency = 1
	tooltipLabel.Text = "Prevents you from dropping enlighten on drop."
	tooltipLabel.TextColor3 = Color3.new(1, 1, 1)
	tooltipLabel.TextSize = 14
	tooltipLabel.TextXAlignment = Enum.TextXAlignment.Left
	tooltipLabel.TextYAlignment = Enum.TextYAlignment.Top
	tooltipLabel.Font = Enum.Font.GothamSemibold
	tooltipLabel.TextWrapped = true
	tooltipLabel.Size = UDim2.new(0, 200, 0, 0)
	tooltipLabel.AutomaticSize = Enum.AutomaticSize.Y
	tooltipLabel.ZIndex = 101
	
	AntiEnliTickBox.MouseEnter:Connect(function()
		local abs = AntiEnliTickBox.AbsolutePosition
		local size = AntiEnliTickBox.AbsoluteSize
		tooltipFrame.Position = UDim2.new(0, abs.X + size.X + 10, 0, abs.Y)
		tooltipFrame.Visible = true
	end)
	AntiEnliTickBox.MouseLeave:Connect(function()
		tooltipFrame.Visible = false
	end)
	
	-- ============================================================
	-- STATE
	-- ============================================================
	local isEnabled = false
	local connections = {}
	
	-- ============================================================
	-- ENLIGHTEN NAMES (add variations if needed)
	-- ============================================================
	local ENLIGHTEN_NAMES = {
		"Enlighten",
		"The Arkenstone",
		"Arkenstone"
	}
	
	local function isEnlighten(tool)
		if not tool:IsA("Tool") then return false end
		for _, name in ipairs(ENLIGHTEN_NAMES) do
			if tool.Name:lower():find(name:lower()) then
				return true
			end
		end
		return false
	end
	
	-- ============================================================
	-- MONITOR TOOL DROPS
	-- ============================================================
	local function monitorEnlighten(tool)
		if not isEnlighten(tool) then return end
	
		local conn = tool.AncestryChanged:Connect(function()
			if not isEnabled then return end
	
			-- If Enlighten is dropped into workspace, pick it back up immediately
			if tool.Parent == workspace then
				task.wait(0.05) -- Small delay to ensure it's fully dropped
	
				local char = LocalPlayer.Character
				local hum = char and char:FindFirstChildWhichIsA("Humanoid")
	
				if hum and hum.Health > 0 then
					pcall(function()
						hum:EquipTool(tool)
					end)
				end
			end
		end)
	
		table.insert(connections, conn)
	end
	
	-- ============================================================
	-- SETUP CHARACTER
	-- ============================================================
	local function setupCharacter(char)
		-- Monitor existing tools in character
		for _, tool in ipairs(char:GetChildren()) do
			monitorEnlighten(tool)
		end
	
		-- Monitor tools in backpack
		for _, tool in ipairs(LocalPlayer.Backpack:GetChildren()) do
			monitorEnlighten(tool)
		end
	
		-- Monitor new tools added to character
		local charConn = char.ChildAdded:Connect(function(child)
			if isEnabled then
				monitorEnlighten(child)
			end
		end)
		table.insert(connections, charConn)
	
		-- Monitor new tools added to backpack
		local backpackConn = LocalPlayer.Backpack.ChildAdded:Connect(function(child)
			if isEnabled then
				monitorEnlighten(child)
			end
