		local abs = AntiNanTickBox.AbsolutePosition
		local size = AntiNanTickBox.AbsoluteSize
		tooltipFrame.Position = UDim2.new(0, abs.X + size.X + 10, 0, abs.Y)
		tooltipFrame.Visible = true
	end)
	AntiNanTickBox.MouseLeave:Connect(function()
		tooltipFrame.Visible = false
	end)
	
	local function isNaN(n)
		return n ~= n
	end
	
	local function isSafe(cf)
		local p = cf.Position
		return not (isNaN(p.X) or isNaN(p.Y) or isNaN(p.Z) or
			math.abs(p.X) == math.huge or
			math.abs(p.Y) == math.huge or
			math.abs(p.Z) == math.huge)
	end
	
	local function onCharacterAdded(character)
		if not isEnabled then return end
	
		local hrp = character:WaitForChild("HumanoidRootPart")
	
		hrp.Anchored = true
	
		task.wait(0.1)
	
		if not isSafe(hrp.CFrame) then
			hrp.CFrame = CFrame.new(0, 50, 0)
		end
	
		for _, plr in pairs(Players:GetPlayers()) do
			if plr ~= LocalPlayer and plr.Character and plr.Character:FindFirstChild("HumanoidRootPart") then
				local otherHRP = plr.Character.HumanoidRootPart
				if isSafe(otherHRP.CFrame) then
					hrp.CFrame = otherHRP.CFrame + Vector3.new(0, 5, 0)
					break
				end
			end
		end
	
		hrp.Anchored = false
	end
	
	local function enable()
		isEnabled = true
		AntiNanTickBox.BackgroundColor3 = getAccent()
		connection = LocalPlayer.CharacterAdded:Connect(onCharacterAdded)
		if LocalPlayer.Character then
			onCharacterAdded(LocalPlayer.Character)
		end
	end
	
	local function disable()
		isEnabled = false
		AntiNanTickBox.BackgroundColor3 = Color3.new(0, 0, 0)
		if connection then
			connection:Disconnect()
			connection = nil
		end
	end
	
	AntiNanTickBox.MouseButton1Click:Connect(function()
		if isEnabled then
			disable()
		else
			enable()
		end
	end)
	
	script.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			disable()
			tooltipFrame:Destroy()
		end
	end)
end;
