				return v
			end
		end
	end
	
	local UnanchorRepTickBox = findDescendant("UnanchorRepTickBox")
	local RichTextRepTickBox = findDescendant("RichTextRepTickBox")
	
	-- ============================================================
	-- TOOLTIP BUILDER
