			if success then
				BKitFixButton.Text = "FIXED!"
				task.wait(3)
				BKitFixButton.Text = originalText
			else
				BKitFixButton.Text = "FAILED"
				task.wait(3)
				BKitFixButton.Text = originalText
			end
		end)
	end)
	
	-- ============================================================
	-- CLEANUP
	-- ============================================================
	script.AncestryChanged:Connect(function()
		if not script:IsDescendantOf(game) then
			tooltipFrame:Destroy()
		end
	end)
end;
