		local rows = getRows()
		if isMinimized then
			ExploitsGroup.Size = minimizedSize
			for _, row in ipairs(rows) do
				row.Visible = false
			end
			ExploitsMinimize.Text = "+"
		else
			ExploitsGroup.Size = originalSize
			for _, row in ipairs(rows) do
				row.Visible = true
			end
			ExploitsMinimize.Text = "-"
		end
	end)
