		end
	end
	
	local BOTTOM_BAR_HEIGHT = ROW_HEIGHT + 2
	local TOTAL_BOTTOM_HEIGHT = (BOTTOM_BAR_HEIGHT * 2) + 1
	
	-- ============================================================
