	searchPad.Parent = searchBox
	
	local searchArrow = Instance.new("TextButton")
	searchArrow.Size = UDim2.new(0, 24, 0, ROW_HEIGHT)
	searchArrow.Position = UDim2.new(1, -24, 0, 0)
