-- StarterGui.AgarWareGui.MainFrame.ContentArea.MenuPage.MenuLeftSide.ServerGroup.ServerInfoFrame.ServerInfoText.ServerInfoScript
local function C_2af()
local script = G2L["2af"];
	local Players = game:GetService("Players")
	local HttpService = game:GetService("HttpService")
	local RunService = game:GetService("RunService")
	local ServerInfoText = script.Parent
	
	-- Server start time for uptime
	local serverStartTime = tick()
	
	-- Region data
	local regionCode = "N/A"
	
	-- Function to format uptime
	local function formatUptime(seconds)
		local hours = math.floor(seconds / 3600)
		local minutes = math.floor((seconds % 3600) / 60)
		local secs = math.floor(seconds % 60)
		return string.format("%dh %dm %ds", hours, minutes, secs)
	end
	
	-- Function to get ping
	local function getPing()
		local player = Players.LocalPlayer
		if player then
			local pingInSeconds = player:GetNetworkPing()
			return math.round(pingInSeconds * 1000)
		end
		return 0
	end
	
	-- Function to fetch region
	local function updateRegion()
		local url = "http://ip-api.com/json/?fields=16394"
	
		local success, response = pcall(function()
			return HttpService:GetAsync(url)
		end)
	
		if success then
			local data = HttpService:JSONDecode(response)
			if data.status == "success" and data.countryCode then
				regionCode = data.countryCode
			else
				regionCode = "N/A"
			end
		else
			regionCode = "N/A"
		end
	end
	
	-- Update server info display
	local function updateServerInfo()
		local playerCount = #Players:GetPlayers()
		local maxPlayers = Players.MaxPlayers
		local uptime = tick() - serverStartTime
		local latency = getPing()
	
		local text = string.format(
			"👥 Players: %d/%d\n🌐 Region: %s\n⌛ Uptime: %s\n📶 Latency: %dms",
			playerCount,
			maxPlayers,
			regionCode,
			formatUptime(uptime),
			latency
		)
	
		ServerInfoText.Text = text
	end
	
	-- Fetch region on start and every 60 seconds
	updateRegion()
	task.spawn(function()
		while true do
			task.wait(60)
			updateRegion()
		end
	end)
	
	-- Update display every frame
	RunService.Heartbeat:Connect(function()
		updateServerInfo()
	end)
	
	-- Initial update
	updateServerInfo()
end;
task.spawn(C_2af);
