-- StarterGui.AgarWareGui.KeybindFrame.KeybindDragScript
local function C_2c7()
local script = G2L["2c7"];
	-- KeybindDragScript
	-- Handles dragging the KeybindFrame with mobile touch support
	
	local KeybindFrame = script.Parent
	local DragButton = KeybindFrame.DragGUI
	local UserInputService = game:GetService("UserInputService")
	
	-- Drag state variables
	local dragging = false
	local dragStart = nil
	local startPos = nil
	local dragInput = nil
	
	local function updateDrag(input)
		local delta = input.Position - dragStart
		KeybindFrame.Position = UDim2.new(
			startPos.X.Scale,
			startPos.X.Offset + delta.X,
			startPos.Y.Scale,
			startPos.Y.Offset + delta.Y
		)
	end
	
	-- Handle both mouse and touch input
	DragButton.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			dragStart = input.Position
			startPos = KeybindFrame.Position
			dragInput = input
			
			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					dragging = false
					dragInput = nil
				end
			end)
		end
	end)
	
	DragButton.InputChanged:Connect(function(input)
		if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
			updateDrag(input)
		end
	end)
	
	-- Also handle input ended on the button itself
	DragButton.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = false
			dragInput = nil
		end
	end)
	
end;
